+function captureConsole() {
+  const logs: string[] = [];
+  const originalLog = console.log;
+  console.log = (...args: unknown[]) => {
+    logs.push(args.map(String).join(" "));
+  };
+  return {
+    logs,
+    output: () => logs.join("\n"),
+    restore: () => { console.log = originalLog; }
+  };
+}

