+      const capture = captureConsole();
+      try {
+        await infoCommand({});
+        const output = capture.output();
+
+        // Should show either available version or not available
+        expect(output).toMatch(/cass CLI:/i);
+      } finally {
+        capture.restore();
+      }
+    });
+
+    it("shows Bun version when running under Bun", async () => {
